-- Zambrero Brabham (C1405) services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services WHERE customerExternalId = 'C1405';

-- Ma Pa Me (C0155) services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services WHERE customerExternalId = 'C0155';

-- Zambrero West Pinjarra Southbound (C0399) services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services WHERE customerExternalId = 'C0399';

-- Little Cha Tuggerah (C0148) services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services WHERE customerExternalId = 'C0148';

-- TYS Molendinar (C2599) - already checked, no services. Check if there's a service with TYS in name
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue, customerExternalId FROM services
WHERE planName LIKE '%TYS%' OR planName LIKE '%Molendinar%' OR planName LIKE '%Site Bundle%';

-- Compass Assurance (C0065) - check all services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services WHERE customerExternalId = 'C0065';

-- Nu-Dev (C0176) - check all services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services WHERE customerExternalId = 'C0176';

-- Lead Education (C0135/C2431) - check all services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services WHERE customerExternalId IN ('C0135', 'C2431');

